import { getNeonShape } from "./geometric-shapes";
import { neonPalette } from "./tokens";
import type { NeonPrimitive } from "./primitive-renderer";
import type { NeonTopDownScene, NeonTopDownShape } from "./top-down-scene";

export const laneRunnerSceneIds = [
  "auroraExpanse",
  "cyberMetropolis",
] as const;

export type LaneRunnerSceneId = typeof laneRunnerSceneIds[number];

export interface LaneRunnerSceneOptions {
  sceneId: LaneRunnerSceneId;
  width: number;
  height: number;
  timeMs: number;
  pulseRate?: number;
}

const sceneNames: Record<LaneRunnerSceneId, string> = {
  auroraExpanse: "Aurora Expanse",
  cyberMetropolis: "Cyber Metropolis",
};

const blockShape = getNeonShape("tank-block")!;
const barShape = getNeonShape("tank-bar")!;
const frameShape = getNeonShape("bruiser-frame")!;

export function getLaneRunnerSceneName(sceneId: LaneRunnerSceneId): string {
  return sceneNames[sceneId];
}

export function isLaneRunnerSceneId(value: string): value is LaneRunnerSceneId {
  return (laneRunnerSceneIds as readonly string[]).includes(value);
}

export function createLaneRunnerScene(options: LaneRunnerSceneOptions): NeonTopDownScene {
  switch (options.sceneId) {
    case "cyberMetropolis":
      return createCyberMetropolis(options);
    case "auroraExpanse":
      return createAuroraExpanse(options);
  }
}

function pulse(options: LaneRunnerSceneOptions): number {
  return .72 + Math.sin(options.timeMs / 1000 * (options.pulseRate ?? .8) * Math.PI * 2) * .12;
}

function addLaneFloor(items: NeonPrimitive[], width: number, height: number, colors: { primary: string; secondary: string }, energy: number): void {
  const horizonY = height * .53;
  items.push({ x: width / 2, y: height * .78, width: width * .5, height: height * .43, color: colors.primary, secondaryColor: "#02050e", glow: .08, intensity: .14, shape: "bolt" });
  items.push({ x: width / 2, y: horizonY, width: width * .38, height: 1.5, color: colors.secondary, secondaryColor: neonPalette.whiteHot, glow: .5, intensity: .22 + energy * .14, shape: "bolt" });

  for (let depth = 0; depth < 9; depth++) {
    const t = depth / 8;
    const y = horizonY + t * height * .37;
    const gridWidth = width * (.18 + t * .3);
    items.push({ x: width / 2, y, width: gridWidth, height: 1 + t * 1.8, color: depth % 2 ? colors.secondary : colors.primary, glow: .18, intensity: .12 + energy * .1, shape: "bolt" });
  }

  for (const side of [-1, 1]) {
    items.push({ x: width / 2 + side * width * .245, y: height * .75, width: 1.1, height: height * .44, color: colors.secondary, glow: .22, intensity: .16 + energy * .08, shape: "line", rotation: side * .12 });
    for (let depth = 0; depth < 8; depth++) {
      const t = depth / 7;
      items.push({ x: width / 2 + side * width * (.105 + t * .135), y: horizonY + t * height * .37, width: 1 + t * .8, height: 14 + t * 38, color: colors.secondary, glow: .24, intensity: .12 + energy * .1, shape: "bolt" });
    }
  }
}

function createAuroraExpanse(options: LaneRunnerSceneOptions): NeonTopDownScene {
  const { width, height, timeMs } = options;
  const energy = pulse(options);
  const primitives: NeonPrimitive[] = [];

  addAuroraSky(primitives, width, height, timeMs, energy);
  addDistantMountains(primitives, width, height);
  addLaneFloor(primitives, width, height, { primary: neonPalette.deepBlue, secondary: neonPalette.violet }, energy);
  addAuroraReflections(primitives, width, height, timeMs, energy);

  return { primitives };
}

function addAuroraSky(items: NeonPrimitive[], width: number, height: number, timeMs: number, energy: number): void {
  for (let index = 0; index < 26; index++) {
    const x = width * (((index * 37) % 100) / 100);
    const y = height * (.055 + ((index * 53) % 100) / 360);
    items.push({ x, y, width: 1 + index % 3 * .5, color: neonPalette.whiteHot, glow: .14, intensity: .12 + (index % 4) * .025, shape: "spark" });
  }

  const cloudBands = [
    { y: .145, color: neonPalette.green, secondary: neonPalette.cyan, phase: .0, width: .2, height: .12 },
    { y: .18, color: neonPalette.violet, secondary: neonPalette.pink, phase: 1.7, width: .24, height: .16 },
    { y: .225, color: neonPalette.cyan, secondary: neonPalette.green, phase: 3.1, width: .28, height: .18 },
  ];

  for (const band of cloudBands) {
    for (let segment = 0; segment < 9; segment++) {
      const t = segment / 8;
      const wave = Math.sin(timeMs / 5200 + band.phase + segment * .72);
      const x = width * (.12 + t * .78 + wave * .018);
      const y = height * (band.y + Math.sin(timeMs / 6400 + band.phase + segment * .58) * .035);
      const w = width * (band.width * (.75 + (segment % 3) * .12));
      const h = height * (band.height * (.55 + (segment % 4) * .08));
      items.push({
        x, y, width: w, height: h,
        color: band.color,
        secondaryColor: band.secondary,
        glow: .85,
        intensity: .055 + energy * .035,
        texture: .25,
        rimIntensity: .25,
        shadowStrength: .18,
        shape: "orb",
      });
    }
  }

  for (let sheet = 0; sheet < 11; sheet++) {
    const x = width * (.16 + sheet * .07);
    const drift = Math.sin(timeMs / 3600 + sheet * .8);
    items.push({
      x: x + drift * width * .012,
      y: height * (.25 + Math.sin(timeMs / 4400 + sheet) * .026),
      width: 10 + sheet % 3 * 4,
      height: height * (.23 + sheet % 4 * .025),
      color: sheet % 3 === 0 ? neonPalette.green : sheet % 3 === 1 ? neonPalette.violet : neonPalette.cyan,
      secondaryColor: neonPalette.whiteHot,
      glow: .46,
      intensity: .09 + energy * .055,
      shape: "line",
      rotation: -.12 + drift * .1,
    });
  }
}

function addDistantMountains(items: NeonPrimitive[], width: number, height: number): void {
  for (let index = 0; index < 12; index++) {
    const t = index / 11;
    const x = width * t;
    const y = height * (.48 - Math.sin(index * .93) * .035);
    const size = 30 + (index % 5) * 10;
    items.push({ x, y, width: size, height: size * 1.2, color: "#061024", secondaryColor: neonPalette.deepBlue, glow: .04, intensity: .72, shape: "diamond" });
  }
}

function addAuroraReflections(items: NeonPrimitive[], width: number, height: number, timeMs: number, energy: number): void {
  for (let index = 0; index < 16; index++) {
    const x = width * (.2 + ((index * 41) % 100) / 165);
    const y = height * (.6 + ((index * 67 + timeMs / 120) % 100) / 285);
    items.push({
      x, y,
      width: 1.2 + index % 3,
      height: 18 + index % 5 * 9,
      color: index % 2 ? neonPalette.violet : neonPalette.deepBlue,
      secondaryColor: neonPalette.cyan,
      glow: .32,
      intensity: .12 + energy * .1,
      shape: "bolt",
    });
  }
}

function createCyberMetropolis(options: LaneRunnerSceneOptions): NeonTopDownScene {
  const { width, height, timeMs } = options;
  const energy = pulse(options);
  const primitives: NeonPrimitive[] = [];
  const shapes: NeonTopDownShape[] = [];

  addCityGlow(primitives, width, height, energy);
  addMetropolisBuildings(primitives, shapes, width, height, timeMs, energy);
  addLaneFloor(primitives, width, height, { primary: neonPalette.pink, secondary: neonPalette.cyan }, energy);
  addMetropolisReflections(primitives, width, height, timeMs, energy);

  return { primitives, shapes };
}

function addCityGlow(items: NeonPrimitive[], width: number, height: number, energy: number): void {
  items.push({ x: width / 2, y: height * .45, width: width * .62, height: height * .2, color: neonPalette.pink, secondaryColor: neonPalette.cyan, glow: .72, intensity: .04 + energy * .025, shape: "orb" });
  items.push({ x: width / 2, y: height * .52, width: width * .48, height: 2, color: neonPalette.pink, secondaryColor: neonPalette.whiteHot, glow: .55, intensity: .26 + energy * .14, shape: "bolt" });
}

function addMetropolisBuildings(items: NeonPrimitive[], shapes: NeonTopDownShape[], width: number, height: number, timeMs: number, energy: number): void {
  for (const side of [-1, 1]) {
    for (let index = 0; index < 10; index++) {
      const depth = index / 9;
      const x = width / 2 + side * width * (.25 + depth * .3);
      const baseY = height * (.52 + depth * .035);
      const buildingHeight = height * (.18 + ((index * 29) % 7) * .033 + (1 - depth) * .14);
      const buildingWidth = 16 + depth * 30;
      const centerY = baseY - buildingHeight * .45;
      const shape = index % 3 === 0 ? barShape : index % 3 === 1 ? blockShape : frameShape;
      const color = index % 2 ? neonPalette.violet : neonPalette.pink;

      shapes.push({
        shape,
        x,
        y: centerY,
        size: buildingWidth,
        color,
        glow: .18 + energy * .08,
        opacity: .3,
        rotationX: -.1,
        rotationY: side * (.08 + depth * .08),
        rotationZ: 0,
        lineThickness: .55,
        energyIntensity: .18,
        energyCoverage: .08,
        energySpeed: .28,
        energyBleed: .05,
      });

      items.push({ x, y: centerY, width: buildingWidth * .75, height: buildingHeight, color: "#050816", secondaryColor: color, glow: .04, intensity: .46, shape: "bolt" });
      items.push({ x, y: centerY - buildingHeight * .52, width: 2.2, height: 24 + depth * 28, color, secondaryColor: neonPalette.whiteHot, glow: .5, intensity: .16 + energy * .16, shape: "bolt" });

      const rows = 7 + Math.floor((1 - depth) * 5);
      for (let row = 0; row < rows; row++) {
        const rowY = centerY - buildingHeight * .31 + row * buildingHeight * .055;
        const lit = Math.sin(timeMs / 1800 + index * 1.7 + row * .8) > .18;
        if (!lit) continue;
        for (let col = -1; col <= 1; col++) {
          if ((row + col + index) % 2 === 0) {
            items.push({ x: x + col * buildingWidth * .18, y: rowY, width: 2 + depth * 2, height: 1.1, color, glow: .18, intensity: .1 + energy * .08, shape: "bolt" });
          }
        }
      }
    }
  }
}

function addMetropolisReflections(items: NeonPrimitive[], width: number, height: number, timeMs: number, energy: number): void {
  for (let index = 0; index < 18; index++) {
    const x = width * (.12 + ((index * 47) % 100) / 132);
    const y = height * (.57 + ((index * 59 + timeMs / 90) % 100) / 260);
    items.push({
      x, y,
      width: 1 + index % 3,
      height: 24 + index % 5 * 11,
      color: index % 3 ? neonPalette.pink : neonPalette.cyan,
      secondaryColor: neonPalette.whiteHot,
      glow: .34,
      intensity: .11 + energy * .11,
      shape: "bolt",
    });
  }
}
